#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

screen3 = vec3 ((vUv-0.5),1);
rsl = project ();
vec2 noise = texture(sampler_pw_noise_lq,rsl.xy+rand_frame);

//GLASROHRE
rx = max(min(rsl.x*4.5-2,2),-2)+2;
rsk = vec2(fract(rx)-0.5,(rsl.y-0.88)*3)*2.3 ;
glas_form = sqrt(1-1*pow(rsk.x,2));
glas_uv =   vec2(-rsk.x/glas_form,0);;
glas_mask = clamp01(16-16*abs(rsk.x));
Glas = glas_mask*glas_uv;
int kolb_no = int(rx) % 4;

tmp0= kolb_mov[kolb_no];
tmp = (tmp0 + kolb_base)*kolb_ampl;
glas_mask *= (rsl.y > tmp +glas_form*CorrZ(rsl.y));

vec2 uv2 = vUvOriginal;
dis[0] = uTexSize.zw * vec2(16,0);
dis[1] = uTexSize.zw * vec2(0,30*Freq);
dz.x = 2*GetBlur1 (uv2.xy-dis[0]).r - 2*GetBlur1 (uv2.xy+dis[0]).r;
dz.y = 2*GetBlur1 (uv2.xy-dis[1]).r - 2*GetBlur1 (uv2.xy+dis[1]).r;

//unipolar ueberarbeiten##
dz.y += sat(kolb_speed[kolb_no]) * -16/uFps *  sat(1-4*(rsl.y-tmp));
//dz += glas_uv*0.041; //interessant #

ret.r = (audioLow+audioMid)*exp(-3*max(abs(rsk.x),abs(rsk.y))) *q24 * (kolb_no==q10) ; //nicht mit frequ multiplizieren
//Zuendung klappt nur wenn rsk = 0 noch auf dem Bild

ret.r = max(ret.r, GetPixel(vUv + dz*-0.12).r*fak - 0.002*(noise-0.5))* glas_mask  ;//Rechenzeit#

vec2 uv3 = fract(rsl + vec2(0,-q29*8))-0.5;
uv3 = pow(uv3-vec2(0.4,0),2)*300;
ret.g = sat(1-uv3.y);
ret.g = max(ret.g,sat(1-uv3.x -0.2*(uv3.y>8)));
float test = texture(sampler_pw_noise_lq,rsl*0.05) * (1-rsl.y);
ret.g += (ret.g==0)*test;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

screen3 = vec3 ((vUv-0.5),1);
rsl = project();

rx = max(min(rsl.x*4.5-2,2),-2)+2;
vec2 ypos = vec2 (0.2, (kolb_mov[rx%4] + kolb_base)*kolb_ampl);
vec2 xpos = (fract(rx)-0.5) *vec2 (2.1,2.4);
vec2 xarg = pow(xpos,2);
vec2 form = sqrt(1-xarg);

//FORM GLAS
glas_uv = vec2 (-xpos[0]/form[0], 1.2-form[0]);
glas_form = form[0];
glas_mask =  sat(16-16*xarg[0])* (rsl.y >(ypos[0] +form[0]*CorrZ(rsl.y)));
Glas = glas_mask*glas_uv;

//FORM KOLBEN
float rely = ypos[1]+form[1]*CorrZ(rsl.y)-rsl.y;
xpos[1] *= 1+sat(100*rely-30);
xarg[1] = pow(xpos[1],2);
float ymod = (floor(20*rely))%2 * (rely < 0.3);
kolb_uv = vec2 (-xpos[1]/form[1], ymod-form[1]+1.4); //###
kolb_form = form[1];
tmp = form[1]*CorrZ(rsl.y);
kolb_mask = sat(16-16*xarg[1]*(1+0*ymod)) * ((ypos[1]-tmp)>rsl.y);
kolb_mask2 = (kolb_mask) *  (rsl.y > ypos[1]+tmp);
Kolb = kolb_mask*kolb_uv;

//KOORDINATEN
uv_fire=vUv;
uv_back= vUv + vec2 (Glas.x*-0.05,0);
uv_spiegelf = uv_back; //gleich halten
uv_refl = vUv - vec2 (.1,1.2)*0;

//HINTERGRUND
vec2 rr = uTexSize.zw*2;
dz.x = GetPixel (uv_back-rr).g - GetPixel (uv_back+rr).g - 0.06;
dz.y = 0;
back = GetPixel(uv_back).g  ;

float prof = max(max(back*0,glas_form),kolb_form*0);
float test = fract(q30+(rsl.x-0*rsl.y+prof*0)*0.2)<0.2;
sun = (0.5/length(uv_back+dz*18 +vec2(1.2,0))) * ( 1-vUv.y);
back =  sun * back * vec3 (1,0.7,0.5);

back *= 1-kolb_mask;
ret1 = back;

//FEUER
ret1 *= sat(1-8*GetPixel(vUv).r);
ret1 += lavcol(GetPixel(uv_fire).r) ;


//REFLEKTION KOLBEN
float refk = sat(.06/pow(length(0.2+uv_refl-Kolb),1)) * kolb_mask * !kolb_mask2;
ret1 += refk* !test;
ret1 += (vec3(glow,glow/8,0)* (1-3*rely) * (1+kolb_mask2/2*0)) *kolb_mask;

//TRANSMISSION GLAS
float gg = glas_mask/glas_form;
ret1 = ret1-.05*gg;
ret1 += .16*vec3(0,1,1) * (1-rsl.y)*gg * !test;

//REFLEKTTION GLAS
float refg = (.04/length((uv_refl-Glas*2+0))) * gg;
ret1 += refg*!test;
ret1 += GetPixel(uv_spiegelf).r*vec3(2,0.8,0.5) * (glas_form > 0.1);
ret = ret1;

//ret = GetPixel(vUv).g;

  fragColor = ret;
}
